nta.declaration:
/**TODOS:**
 - Pre-trained production units
*/

/**
Every production unit has two outputs which feed into other production units or to outlets.
If a production unit doesn't receive output from another unit, it receives it from an intake that delivers material according to a cyclic pattern.
*/
clock time;    // Used as exit condition for the strategy queries
clock t;       // I know. This one is a clock that resets each period.
broadcast chan choose;
const int N_UNITS = 10; // Number of units
const int N_provider_out = 10; // Number of providers
typedef int[1, N_UNITS] unitid_t;
typedef int[1, N_provider_out] providerid_t;

const double MIN_STORED = 2;       // Unit: L
const double MAX_STORED = 50;      // Unit: L
const double RATE = 2.65;    // Flow rate through single pipe. Unit: L/m
const double VARIANCE = 0.5; // Flow rate diverges with 0 to +VARIANCE at each time-step.
const double PERIOD = 2.5;    // Length of period for consumer and provider patterns. 

// Material stored in each tank. Unit: L
clock stored[unitid_t] = {11, 11, 11, 11, 11, 11, 11, 11, 11, 11};

// Current outflow rate from production units. Can be influenced by multiple other  units.  Unit: L/m
double unit_out[unitid_t];

// Current outflow rate from providers. Used to calculate cost. Can be influence by multiple production units. Unit: L/m
double provider_out[providerid_t];

// Cost per litre for the given provider. Unit: moneydollars/L
double cost_multiplier[providerid_t] = { 0.5, 0.5, 0.5, 1.0, 1.0, 3.0, 3.0, 3.0, 5.0, 5.0};
clock cost;


/** Shielding **/

const int INPUT_THREE = 3;
const int INPUT_TWO = 2;
const int INPUT_ONE = 1;
const int WAIT = 0;

import "%shield path%"
{
    int get_value(double volume);
};


typedef struct {
    bool wait;
    bool input_one;
    bool input_two;
    bool input_three;
} allowedActions;

allowedActions intToActions(int bitarray) {
    allowedActions result = { 
        (0 != (bitarray & (1 << 0))),
        (0 != (bitarray & (1 << 1))),
        (0 != (bitarray & (1 << 2))),
        (0 != (bitarray & (1 << 3)))
    };
    return result;
}

int debugUnsafeState = 0;

allowedActions get_allowed(double stored) {
    allowedActions allowed = intToActions(get_value(stored));
    allowedActions any = {true, true, true, true};
    if (!allowed.wait && !allowed.input_one && !allowed.input_two && !allowed.input_three) {
        debugUnsafeState = 1;
        return any;
    }
    return allowed;
}

template.declaration:
allowedActions allowed = { true, true, true, true };

// inflow
double in = 0;
double r1, r2, r3;

allowedActions allowed = { true, true, true, true };

// inflow
double in = 0;
double r1, r2, r3;

nta.system:
/** Layout: https://i.imgur.com/qZdiKOI.png
Lines show pipes providing material to next layer.
Boxes signify production units. No box signifies a provider.
D1 and D2 are consumers.
*/ 

P1 = Provider(provider_out[1], cost_multiplier[1], 1.0, 0.5, 0.5, 0.0, 3.0);
P2 = Provider(provider_out[2], cost_multiplier[2], 1.0, 0.5, 0.5, 0.0, 3.0);
P3 = Provider(provider_out[3], cost_multiplier[3], 1.0, 0.5, 0.5, 0.0, 3.0);

U1 = ControllableProductionUnit(1, unit_out[1], stored[1], provider_out[1], provider_out[1], provider_out[1]);
U2 = ControllableProductionUnit(2, unit_out[2], stored[2], provider_out[2], provider_out[2], provider_out[2]);
U3 = ControllableProductionUnit(3, unit_out[3], stored[3], provider_out[3], provider_out[3], provider_out[3]);

P4 = Provider(provider_out[4], cost_multiplier[4], 2.0, 1.5, 1.5, 0.5, 4.0);
P5 = Provider(provider_out[5], cost_multiplier[5], 2.0, 1.5, 1.5, 0.5, 4.0);

U4 = ControllableProductionUnit(4, unit_out[4], stored[4], provider_out[4], unit_out[1], unit_out[2]);
U5 = ControllableProductionUnit(5, unit_out[5], stored[5], unit_out[2], unit_out[3], provider_out[5]);

P6 = Provider(provider_out[6], cost_multiplier[6], 3.0, 3.5, 3.5, 2.5, 2.0);
P7 = Provider(provider_out[7], cost_multiplier[7], 3.0, 3.5, 4.5, 2.5, 2.0);
P8 = Provider(provider_out[8], cost_multiplier[8], 3.0, 4.5, 2.5, 2.5, 2.0);

U6 = ControllableProductionUnit(6, unit_out[6], stored[6], provider_out[6], provider_out[6], unit_out[4]);
U7 = ControllableProductionUnit(7, unit_out[7], stored[7], unit_out[4], unit_out[5], provider_out[7]);
U8 = ControllableProductionUnit(8, unit_out[8], stored[8], unit_out[5], provider_out[8], provider_out[8]);

P9 = Provider(provider_out[9], cost_multiplier[9], 6.0, 6.5, 8.5, 2.5, 2.0);
P10 = Provider(provider_out[10], cost_multiplier[10], 6.0, 6.5, 8.5, 0.5, 6.0);

U9 = ControllableProductionUnit(9, unit_out[9], stored[9], provider_out[9], unit_out[6], unit_out[7]);
U10 = ControllableProductionUnit(10, unit_out[10], stored[10], unit_out[7], unit_out[8], provider_out[10]);

D1 = Consumer(unit_out[9], 0.0, 2*RATE, 2*RATE, RATE, 0.0);
D2 = Consumer(unit_out[10], RATE, RATE, 0.0, 2*RATE, RATE);
system Metronome, P1, P2, P3, U1, U2, U3, P4, P5, U4, U5, P6, P7, P8, U6, U7, U8, P9, P10, U9, U10, D1, D2;

query.formula:
strategy centralized = minE(cost) [<=100] {}->{
    t, stored[1], stored[2], stored[3], stored[4], stored[5], stored[6], stored[7], stored[8], stored[9], stored[10]
}: <> time >= 100
